1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
18	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
19	    const sorted = (arr: [number, number][]) =>
20	      [...arr].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
21	    expect(sorted(result)).toEqual(sorted([[0, 0], [0, 1], [1, 0], [1, 1]]));
22	  });
23	  it("should keep a live cell alive when it has 2 or 3 live neighbors (survival)", () => {
24	    // Vertical blinker: center cell (1,1) has exactly 2 live neighbors
25	    const result = nextGeneration([[1, 0], [1, 1], [1, 2]]);
26	    const resultSet = new Set(result.map(([x, y]) => `${x},${y}`));
27	    expect(resultSet.has("1,1")).toBe(true);
28	  });
29	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
30	    // Plus-shaped pattern: center (1,1) has 4 live neighbors
31	    const cells: [number, number][] = [
32	      [1, 1], // center - has 4 neighbors, should die
33	      [0, 1], // left
34	      [2, 1], // right
35	      [1, 0], // bottom
36	      [1, 2], // top
37	    ];
38	    const result = nextGeneration(cells);
39	    const resultSet = new Set(result.map(([x, y]) => `${x},${y}`));
40	    expect(resultSet.has("1,1")).toBe(false);
41	  });
42	  it.todo("should produce a stable block pattern (still life)");
43	  it.todo("should oscillate a blinker pattern");
44	});
